# scripts/verify_baseline_integrity.py
# Run in CI to prevent tampering: checks that suppressed entries have a reason
import json, sys

with open(".secrets.baseline") as f:
    baseline = json.load(f)

problems = []
for file_path, secrets in baseline.get("results", {}).items():
    for secret in secrets:
        if secret.get("is_verified") or secret.get("is_secret") is False:
            # False-positive suppression must have an explicit reason
            if not secret.get("is_secret") and not secret.get("is_verified"):
                # Unmarked entry — needs audit
                problems.append(
                    f"{file_path}:{secret.get('line_number')}: "
                    f"unaudited secret of type '{secret.get('type')}'"
                )

if problems:
    print("BASELINE AUDIT REQUIRED — unaudited entries:")
    for p in problems:
        print(f"  {p}")
    print("\nRun: detect-secrets audit .secrets.baseline")
    sys.exit(1)

print(f"Baseline OK: {sum(len(v) for v in baseline.get('results', {}).values())} audited entries")
